import java.io.*;
import java.util.*;

public class Main {
    static class Edge {
        int to;
        long w;
        Edge(int t, long w) { this.to = t; this.w = w; }
    }

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder out = new StringBuilder();
        String firstLine = br.readLine();
        while (firstLine != null && firstLine.trim().isEmpty()) {
            firstLine = br.readLine();
        }
        if (firstLine == null) return;
        String[] firstParts = firstLine.trim().split("\\s+");
        int testCases;
        Queue<String> pending = new ArrayDeque<>();
        if (firstParts.length == 1) {
            testCases = Integer.parseInt(firstParts[0]);
        } else {
            testCases = 1;
            pending.add(firstLine);
        }
        for (int t = 0; t < testCases; t++) {
            String line;
            if (!pending.isEmpty()) {
                line = pending.poll();
            } else {
                line = br.readLine();
                while (line != null && line.trim().isEmpty()) {
                    line = br.readLine();
                }
            }
            if (line == null) break;
            StringTokenizer st = new StringTokenizer(line);
            int N = Integer.parseInt(st.nextToken());
            int M = Integer.parseInt(st.nextToken());
            List<Edge>[] adj = new ArrayList[N + 1];
            for (int i = 1; i <= N; i++) adj[i] = new ArrayList<>();
            for (int i = 0; i < M; i++) {
                st = new StringTokenizer(br.readLine());
                int u = Integer.parseInt(st.nextToken());
                int v = Integer.parseInt(st.nextToken());
                long w = Long.parseLong(st.nextToken());
                adj[u].add(new Edge(v, w));
                adj[v].add(new Edge(u, w));
            }
            long[] dist = new long[N + 1];
            Arrays.fill(dist, Long.MAX_VALUE);
            dist[1] = 0;
            PriorityQueue<long[]> pq = new PriorityQueue<>(Comparator.comparingLong(a -> a[0]));
            pq.offer(new long[]{0, 1});
            boolean[] visited = new boolean[N + 1];
            while (!pq.isEmpty()) {
                long[] cur = pq.poll();
                long d = cur[0];
                int node = (int) cur[1];
                if (visited[node]) continue;
                visited[node] = true;
                for (Edge e : adj[node]) {
                    if (dist[e.to] > d + e.w) {
                        dist[e.to] = d + e.w;
                        pq.offer(new long[]{dist[e.to], e.to});
                    }
                }
            }
            for (int i = 1; i <= N; i++) {
                if (dist[i] == Long.MAX_VALUE) out.append("-1");
                else out.append(dist[i]);
                if (i < N) out.append(' ');
            }
            out.append('\n');
        }
        System.out.print(out.toString());
    }
}

